def bubble_sort(mut xs: List[Int]) -> Int:
    var n: Int = len(xs)
    var swaps: Int = 0
    var i: Int = 0
    while i < n:
        var j: Int = 0
        while j < n - i - 1:
            if xs[j] > xs[j + 1]:
                var tmp: Int = xs[j]
                xs[j] = xs[j + 1]
                xs[j + 1] = tmp
                swaps += 1
            j += 1
        i += 1
    return swaps

def main():
    var xs: List[Int] = [5, 3, 8, 1, 4]
    print(bubble_sort(xs))
