def digit_sum(var n: Int) -> Int:
    var total: Int = 0
    while n > 0:
        total += n % 10
        n = n // 10
    return total

def is_harshad(n: Int) -> Bool:
    var s: Int = digit_sum(n)
    if s == 0:
        return False
    return n % s == 0

